import fs from "fs";
import path from "path";
import { NextRequest, NextResponse } from "next/server";
import { db } from "@/lib/db";
import { createWorker } from "tesseract.js";

export const config = {
  api: { bodyParser: false },
};

async function processFileWithTesseract(filePath: string) {
  try {
    const worker = await createWorker({
      logger: (m) => console.log(m), // Logs progress
      workerPath: path.join(
        process.cwd(),
        "node_modules/tesseract.js/src/worker/worker.js"
      ),
      langPath: path.join(process.cwd(), "node_modules/tesseract.js/tessdata"),
      corePath: path.join(
        process.cwd(),
        "node_modules/tesseract.js-core/tesseract-core.wasm.js"
      ),
    });

    await worker.loadLanguage("eng");
    await worker.initialize("eng");

    const { data } = await worker.recognize(filePath);
    await worker.terminate(); // Clean up worker

    return { text: data.text, isMarksheet: true };
  } catch (error) {
    console.error("Error with Tesseract.js:", error);
    return { error: "Tesseract processing failed", isMarksheet: false };
  }
}


// Function to extract obtained marks from OCR text
function extractMarks(text: string) {
  const marksPattern = /\b(\d{2,3})\b/g; // Extracts numbers with 2-3 digits
  const marks = [...text.matchAll(marksPattern)].map((match) =>
    parseInt(match[0])
  );

  // Remove unrealistic marks (e.g., above 100)
  const obtainedMarks = marks.filter((mark) => mark <= 100);
  const totalMarks = obtainedMarks.length * 100;

  return {
    obtainedMarks: obtainedMarks.reduce((a, b) => a + b, 0),
    totalMarks,
  };
}

// Function to check eligibility
function checkEligibility(obtained: number, total: number) {
  if (total === 0) return { percentage: 0, eligibility: "Invalid data" };
  const percentage = (obtained / total) * 100;
  const eligibility =
    percentage >= 50
      ? "Eligible for the program."
      : "Sorry, you are not eligible.";

  return { percentage: percentage.toFixed(2), eligibility };
}

// Main API handler
export async function POST(req: NextRequest) {
  try {
    const { email } = await req.json();

    // Fetch user from DB
    const [user] = await db.query("SELECT * FROM users WHERE email = ?", [
      email,
    ]);

    if (!user.length) {
      return NextResponse.json({ error: "User not found" }, { status: 404 });
    }

    const filePath1 = path.join("./public", user[0].tenth_certificate);
    const filePath2 = path.join("./public", user[0].twelfth_certificate);

    if (!fs.existsSync(filePath1) || !fs.existsSync(filePath2)) {
      return NextResponse.json({ error: "Files not found" }, { status: 404 });
    }

    // Process both certificates
    const result1 = await processFileWithTesseract(filePath1);
    const result2 = await processFileWithTesseract(filePath2);

    if (result1.error || result2.error) {
      return NextResponse.json(
        { error: "OCR processing failed" },
        { status: 500 }
      );
    }

    // Extract marks and calculate eligibility
    const marks1 = extractMarks(result1.text);
    const marks2 = extractMarks(result2.text);

    const eligibility1 = checkEligibility(
      marks1.obtainedMarks,
      marks1.totalMarks
    );
    const eligibility2 = checkEligibility(
      marks2.obtainedMarks,
      marks2.totalMarks
    );

    return NextResponse.json(
      {
        tenth_result: { ...eligibility1, isMarksheet: result1.isMarksheet },
        twelfth_result: { ...eligibility2, isMarksheet: result2.isMarksheet },
      },
      { status: 200 }
    );
  } catch (error) {
    console.error("Error processing files:", error);
    return NextResponse.json(
      { error: "Error processing files" },
      { status: 500 }
    );
  }
}
